@startuml
!theme plain

title CATEGORY's Class Diagram

package "jp" {
  package "ac" {
    package "shibaura" {
      package "it" {
        package "ie" {
          package "domain" {
            package "model" {
              package "category" {
                class "CategoryRepository" as CategoryRepository {
                  <<interface>>
                }
              }
            }
          }
          package "gateways" {
            package "category" {
              class "MySQLCategoryRepository" as MySQLCategoryRepository {
                <<class>>
                + findAll()
                + save()
              }
            }
          }
        }
      }
    }
  }
}

CategoryRepository <|-- MySQLCategoryRepository

@enduml
